#include <stdio.h>
#include <string.h>

int result(const char *a, const char *b) {
    if (strcmp(a, b) == 0) return 0;
    // Rock
    if (strcmp(a, "Rock") == 0) {
        if (strcmp(b, "Scissors") == 0 || strcmp(b, "Water") == 0) return 1;
        return -1; // Paper
    }
    // Paper
    if (strcmp(a, "Paper") == 0) {
        if (strcmp(b, "Rock") == 0) return 1;
        if (strcmp(b, "Scissors") == 0 || strcmp(b, "Water") == 0) return -1;
    }
    // Scissors
    if (strcmp(a, "Scissors") == 0) {
        if (strcmp(b, "Paper") == 0 || strcmp(b, "Water") == 0) return 1;
        return -1; // Rock
    }
    // Water
    if (strcmp(a, "Water") == 0) {
        if (strcmp(b, "Paper") == 0 || strcmp(b, "Scissors") == 0) return 1;
        if (strcmp(b, "Rock") == 0) return -1;
    }
    return 0; // should never reach
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char you[20], comp[20];
        int youScore = 0, compScore = 0;
        for (int i = 1; i <= N; ++i) {
            scanf("%s %s", you, comp);
            int r = result(you, comp);
            if (r == 1) { ++youScore; printf("Round %d: You\n", i); }
            else if (r == -1) { ++compScore; printf("Round %d: Computer\n", i); }
            else { printf("Round %d: Tie\n", i); }
        }
        if (youScore > compScore) printf("You won the overall match\n");
        else if (compScore > youScore) printf("Computer won the overall match\n");
        else printf("Match tied\n");
    }
    return 0;
}

