import java.io.*;
import java.util.*;
public class Main {
    private static int result(String a, String b) {
        if (a.equals(b)) return 0;
        switch (a) {
            case "Rock":
                if (b.equals("Scissors") || b.equals("Water")) return 1;
                return -1; // Paper
            case "Paper":
                if (b.equals("Rock")) return 1;
                if (b.equals("Scissors") || b.equals("Water")) return -1;
                break;
            case "Scissors":
                if (b.equals("Paper") || b.equals("Water")) return 1;
                return -1; // Rock
            case "Water":
                if (b.equals("Paper") || b.equals("Scissors")) return 1;
                if (b.equals("Rock")) return -1;
                break;
        }
        return 0;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            int youScore = 0, compScore = 0;
            for (int i = 1; i <= N; i++) {
                st = new StringTokenizer(br.readLine());
                String you = st.nextToken();
                String comp = st.nextToken();
                int r = result(you, comp);
                if (r == 1) { youScore++; out.append("Round ").append(i).append(": You\n"); }
                else if (r == -1) { compScore++; out.append("Round ").append(i).append(": Computer\n"); }
                else out.append("Round ").append(i).append(": Tie\n");
            }
            if (youScore > compScore) out.append("You won the overall match\n");
            else if (compScore > youScore) out.append("Computer won the overall match\n");
            else out.append("Match tied\n");
        }
        System.out.print(out.toString());
    }
}

