import sys

def result(a, b):
    if a == b:
        return 0
    if a == "Rock":
        return 1 if b in ("Scissors", "Water") else -1
    if a == "Paper":
        if b == "Rock":
            return 1
        return -1 if b in ("Scissors", "Water") else 0
    if a == "Scissors":
        return 1 if b in ("Paper", "Water") else -1
    if a == "Water":
        return 1 if b in ("Paper", "Scissors") else -1 if b == "Rock" else 0
    return 0

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    idx = 0
    T = int(data[idx]); idx += 1
    out_lines = []
    for _ in range(T):
        N = int(data[idx]); idx += 1
        you_score = comp_score = 0
        for i in range(1, N+1):
            you, comp = data[idx].split(); idx += 1
            r = result(you, comp)
            if r == 1:
                you_score += 1
                out_lines.append(f"Round {i}: You")
            elif r == -1:
                comp_score += 1
                out_lines.append(f"Round {i}: Computer")
            else:
                out_lines.append(f"Round {i}: Tie")
        if you_score > comp_score:
            out_lines.append("You won the overall match")
        elif comp_score > you_score:
            out_lines.append("Computer won the overall match")
        else:
            out_lines.append("Match tied")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    main()

